Here are the public test cases for feature4_1_default_state:
{
  "description": "Reduce with no action (or an unrecognized action) returns the current state unchanged; an absent state yields the initial state whose active route is / and whose route table is empty.",
  "cases": [
    {
      "input": {
        "op": "reduce"
      },
      "expected_output": "activeRoute=/"
    },
    {
      "input": {
        "op": "reduce",
        "state": {
          "activeRoute": "/about",
          "routes": {}
        }
      },
      "expected_output": "activeRoute=/about"
    }
  ]
}

Here are the public test cases for feature4_2_add_route_reduction:
{
  "description": "Reduce an add-route command: the path is inserted into the route table, and its active flag is computed against the current active route at insertion time.",
  "cases": [
    {
      "input": {
        "op": "reduce",
        "action": {
          "path": "/contact",
          "type": "ADD_ROUTE"
        }
      },
      "expected_output": "activeRoute=/\nroute[/contact].active=false"
    },
    {
      "input": {
        "op": "reduce",
        "state": {
          "activeRoute": "/contact",
          "routes": {}
        },
        "action": {
          "path": "/contact",
          "type": "ADD_ROUTE"
        }
      },
      "expected_output": "activeRoute=/contact\nroute[/contact].active=true"
    }
  ]
}

Here are the public test cases for feature4_3_set_active_route_reduction:
{
  "description": "Reduce a set-active-route command: the active route becomes the command path and every route in the table is re-evaluated for match and parameters against the new active route.",
  "cases": [
    {
      "input": {
        "op": "reduce",
        "state": {
          "activeRoute": "/",
          "routes": {
            "/about": {
              "active": false,
              "params": {}
            },
            "/contact": {
              "active": false,
              "params": {}
            },
            "/home": {
              "active": false,
              "params": {}
            }
          }
        },
        "action": {
          "path": "/contact",
          "type": "SET_ACTIVE_ROUTE"
        }
      },
      "expected_output": "activeRoute=/contact\nroute[/about].active=false\nroute[/contact].active=true\nroute[/home].active=false"
    },
    {
      "input": {
        "op": "reduce",
        "state": {
          "activeRoute": "/",
          "routes": {
            "/about": {
              "active": false,
              "params": {}
            },
            "/products/:id": {
              "active": false,
              "params": {}
            }
          }
        },
        "action": {
          "path": "/products/shirt",
          "type": "SET_ACTIVE_ROUTE"
        }
      },
      "expected_output": "activeRoute=/products/shirt\nroute[/about].active=false\nroute[/products/:id].active=true\nroute[/products/:id].param.id=shirt"
    },
    {
      "input": {
        "op": "reduce",
        "state": {
          "activeRoute": "/",
          "routes": {
            "/about": {
              "active": false,
              "params": {}
            },
            "/products/:id": {
              "active": false,
              "params": {}
            }
          }
        },
        "action": {
          "path": "/about",
          "type": "SET_ACTIVE_ROUTE"
        }
      },
      "expected_output": "activeRoute=/about\nroute[/about].active=true\nroute[/products/:id].active=false"
    }
  ]
}

